 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import {
 4	  DescriptionList,
 5	  DescriptionListDescription,
 6	  DescriptionListGroup,
 7	  DescriptionListTerm,
 8	} from '@patternfly/react-core';
 9	import { CombinedErrorDetails } from './log-snippet-types';
10	import LogSnippetBlock from './LogSnippetBlock';
11	
12	type RunDetailErrorLogProps = {
13	  logDetails: CombinedErrorDetails;
14	  namespace: string;
15	  isResourceManagedByKueue?: boolean;
16	  pipelineRunName?: string;
17	};
18	
19	const RunDetailsErrorLog: React.FC<RunDetailErrorLogProps> = ({
20	  logDetails,
21	  namespace,
22	  isResourceManagedByKueue,
23	  pipelineRunName,
24	}) => {
25	  const { t } = useTranslation('plugin__pipelines-console-plugin');
26	  if (!logDetails) {
27	    return null;
28	  }
29	
30	  return (
31	    <DescriptionList>
32	      <DescriptionListGroup>
33	        <DescriptionListTerm>{t('Message')}</DescriptionListTerm>
34	        <DescriptionListDescription>
35	          {logDetails.title}
36	        </DescriptionListDescription>
37	      </DescriptionListGroup>
38	      <DescriptionListGroup>
39	        <DescriptionListTerm>{t('Log snippet')}</DescriptionListTerm>
40	        <DescriptionListDescription>
41	          <LogSnippetBlock
42	            logDetails={logDetails}
43	            namespace={namespace}
44	            isResourceManagedByKueue={isResourceManagedByKueue}
45	            pipelineRunName={pipelineRunName}
46	          >
47	            {(logSnippet: string) => <pre className="co-pre">{logSnippet}</pre>}
48	          </LogSnippetBlock>
49	        </DescriptionListDescription>
50	      </DescriptionListGroup>
51	    </DescriptionList>
52	  );
53	};
54	
55	export default RunDetailsErrorLog;

